class MinStack {

    private Node top;
    private Node min;

    public MinStack() {

    }

    public void push(int val) {
        Node node = new Node(val);
        if (top == null) {
            top = node;
            min = node;
        } else {
            node.next = top;
            top = node;
            if (val <= min.val) {
                Node newMin = new Node(val);
                newMin.nextMin = min;
                min = newMin;
            }
        }
    }

    public void pop() {
        if (top.val == min.val) {
            min = min.nextMin;
        }
        top = top.next;
    }

    public int top() {
        return top.val;
    }

    public int getMin() {
        return min.val;
    }

    private class Node {
        int val;
        Node next;
        Node nextMin;

        public Node(int val) {
            this.val = val;
        }
    }
}
